// 1. Sadə type annotations
let userName: string = "Murad"; // Yalnız sətir
let userAge: number = 23; // Yalnız rəqəm
let isActive: boolean = true; // Yalnız true/false
// userName = 23; // Xəta: number string tipinə uyğun deyil

// 2. Funksiyalarda type annotations
function greet(name: string): string {
  return `Salam, ${name}!`;
}
// greet(123); // Xəta: number string tipinə uyğun deyil

// 3. Obyektlərdə type annotations
interface Product {
  name: string;
  price: number;
}
const item: Product = { name: "Laptop", price: 1200 };
// item.price = "1000"; // Xəta: string number tipinə uyğun deyil

// 4. Array-lərdə type annotations
let prices: number[] = [10, 20, 30]; // Yalnız rəqəmlər
// prices.push("40"); // Xəta: string number[] tipinə uyğun deyil

// 5. Union type ilə type annotations
type ID = string | number;
let orderId: ID = "A123"; // Və ya rəqəm: 123

// 6. Literal type ilə type annotations
type Status = "pending" | "shipped";
let orderStatus: Status = "pending"; // Yalnız bu dəyərlər

// 7. Type alias ilə type annotations
type User = {
  name: string;
  age: number;
};
const user: User = { name: "Alice", age: 25 };

// Sadə mağaza sistemi
interface Product {
  name: string;
  price: number;
}

type ShowProduct = (product: Product) => string;
const showProduct: ShowProduct = (product) => {
  return `${product.name}: $${product.price}`;
};

const laptop: Product = { name: "Laptop", price: 1200 };
const mouse: Product = { name: "Mouse", price: 25 };
console.log(showProduct(laptop)); // Çıxış: Laptop: $1200
console.log(showProduct(mouse)); // Çıxış: Mouse: $25

